//
import { HORIZONTAL_ALIGN } from '../../core/align-constants';
import { $ZCG } from '../../core/zcglobal';
import { Registry } from '../../core/zc-registry';
import { getTextHeight } from '../../label/font-helpers';

function ExpandableAdjustFactor(config = {}, w, h, globalFont, align, padding = 3) {
    let isHorizontal = align.layout === HORIZONTAL_ALIGN,
        { show, keepAligned } = config,
        adjust = [0, 0];

    if (show) {
        if (isHorizontal && keepAligned) {
            adjust[0] += w * 0.2 + padding * 2;
        } else {
            adjust[1] += getTextHeight([config, globalFont, $ZCG]) + padding * 2;
        }
    }

    return adjust;
}

export { ExpandableAdjustFactor };
Registry.setComponent('expandable.adjust', ExpandableAdjustFactor);
